        "MasterPrompt":  "{  \"poster_type\": \"Horizontal 3D typographic diorama collage\",  \"style\": \"Hyper-realistic photo-manipulation and miniature 3D modeling, blending typography with cultural landmarks and landscapes\",  \"context\": \"A creative travel campaign or global conceptual illustration spelling out the word \u0027[WORD_TO_SPELL]\u0027, where each letter is a standalone miniature world representing the cultural identity of [LOCATION_OR_CULTURE_NAME]\",  \"visual_elements\": {    \"main_typography\": {      \"text\": \"[WORD_TO_SPELL]\",      \"structure\": \"Massive, thick 3D letters standing in a horizontal line. Some letters are [COLOR_OR_FINISH_1], while others feature [SPECIFIC_CULTURAL_PATTERNS], traditional [CULTURAL_STYLE] motifs, and [MATERIAL_TEXTURES] inspired by [SPECIFIC_CRAFTSMANSHIP].\",      \"interaction\": \"The letters act as physical foundations. Elements of the dioramas such as [ACTIVITY_OR_OBJECT_1], [ACTIVITY_OR_OBJECT_2], [ACTIVITY_OR_OBJECT_3], and [ACTIVITY_OR_OBJECT_4] interact directly with the 3D geometry—resting on top, leaning against, or wrapping around them.\"    },    \"thematic_dioramas\": {      \"description\": \"Each individual letter from \u0027[WORD_TO_SPELL]\u0027 is densely decorated with photorealistic miniature elements representing different aspects of [LOCATION_OR_CULTURE_NAME].\",      \"elements_to_include\": {        \"[LETTER_1]\": \"[DIORAMA_DESCRIPTION_FOR_LETTER_1]\",        \"[LETTER_2]\": \"[DIORAMA_DESCRIPTION_FOR_LETTER_2]\",        \"[LETTER_3]\": \"[DIORAMA_DESCRIPTION_FOR_LETTER_3]\",        \"[LETTER_4]\": \"[DIORAMA_DESCRIPTION_FOR_LETTER_4]\",        \"[LETTER_5]\": \"[DIORAMA_DESCRIPTION_FOR_LETTER_5]\",        \"[LETTER_6]\": \"[DIORAMA_DESCRIPTION_FOR_LETTER_6]\"      },      \"text_labels\": \"Small, elegant floating labels near each letter reading: \u0027[LOCATION_OR_CULTURE_FULL_NAME]\u0027\"    },    \"connecting_element\": {      \"description\": \"A thin, continuous, [COLOR] [LINE_STYLE] weaving horizontally through and around the letters, resembling a travel route on a map\",      \"details\": \"The line includes small [COLOR_OF_NODES] nodes and modern map pins, suggesting a guided cultural journey through each scene\"    }  },  \"lighting_and_background\": {    \"background\": \"A solid, clean, minimalist [COLOR] [SETTING] background\",    \"lighting\": \"Bright, even studio lighting with realistic soft drop shadows cast by the letters and objects onto the invisible ground plane, emphasizing depth and 3D realism\"  },  \"restrictions\": {    \"typography_accuracy\": \"CRITICAL RULE: Any [SPECIFIC_LANGUAGE] text included in the image MUST be spelled 100% accurately. Absolutely no garbled text, mutated letters, or incorrect placement of vowels and tone marks. No gibberish. If flawless [SPECIFIC_LANGUAGE] rendering is not possible, render the labels clearly in English instead.\"  }}",
