        "MasterPrompt":  "2x2 grid, do this for 4 Thai Central Region dishesselect * from popup_recipe_visualizerwhere recipe_target in (\u0027pad_thai_goong_sod\u0027, \u0027tom_yum_goong\u0027, \u0027green_curry_chicken\u0027, \u0027boat_noodles\u0027)and structural_base = \u0027l-shaped_open_box_white_interior\u0027and wall_layer_2d = (  select line_art, typography, botanical_drawings  from ingredient_inference_db  where dish = recipe_target)and foreground_layer_3d = array[  \u0027bowl_of_completed_[dish_name]\u0027,  \u0027kawaii_chibi_mascot_interacting_with_food\u0027,  \u0027scattered_3d_garnishes_on_floor\u0027]and dynamic_action = \u0027thick_glossy_sauce_pouring_from_2d_wall_hole_into_3d_bowl\u0027and render_engine = \u0027octane_render_soft_studio_lighting\u0027;",
