        "MasterPrompt":  "{  \"system_core\": {    \"mode\": \"Hybrid Professional Studio\",    \"quality_standard\": \"Commercial Masterpiece\",    \"fail_safe_mechanism\": \"ALWAYS override bad user inputs with professional aesthetic rules.\"  },  \"user_inputs\": {    \"source_image\": null,    \"dish_name\": \"Authentic Thai Noodle Soup (ก๋วยเตี๋ยว)\",    \"mood_tone\": \"Warm Gourmet Street Elegance\",    \"scene_props\": \"\"  },  \"aesthetic_enforcer\": {    \"lighting_setup\": \"Professional studio lighting, soft directional light from left, subtle rim light to separate subject from background, warm reflector fill enhancing broth gloss and noodle texture.\",    \"camera_gear\": \"Shot on Phase One XF IQ4 150MP, 80mm Schneider Kreuznach lens, f/2.8 aperture for creamy bokeh.\",    \"post_processing\": \"Color graded, high contrast, ultra-sharp details, rich and appetizing tones, emphasizing steam, broth clarity, and ingredient freshness in uncompressed RAW quality.\"  },  \"logic_controller\": {    \"scenario_A_image_upload\": {      \"check\": \"User provides \u0027source_image\u0027\",      \"instruction\": \"Keep the noodle dish exactly as is, enhance steam visibility and broth shine, harmonize lighting with professional studio standards, upgrade background into refined Thai dining or premium street-food aesthetic.\"    },    \"scenario_B_text_only\": {      \"check\": \"User provides NO image\",      \"instruction\": \"Generate an appetizing bowl of Thai noodles with glossy broth, perfectly arranged noodles, slices of meat, fresh herbs, bean sprouts, chili flakes, and lime. Steam must be visible to convey freshness. Presentation must be clean, balanced, and visually mouthwatering.\"    }  },  \"smart_scene_selector\": {    \"rule\": \"If \u0027scene_props\u0027 is EMPTY, pick one of these SAFE presets based on dish type:\",    \"presets\": [      {        \"type\": \"Street Food\",        \"scene\": \"Clean wooden table, blurred warm Thai night market lights in background (bokeh), minimal styling, subtle cultural elements\"      },      {        \"type\": \"Luxury/Fine Dining\",        \"scene\": \"Dark textured stone surface, moody lighting, elegant chopsticks and ceramic spoon, refined Thai fusion presentation\"      },      {        \"type\": \"Cafe/Bakery\",        \"scene\": \"Light marble surface, soft morning light, minimal greenery, modern Thai cafe aesthetic\"      }    ]  },  \"final_prompt_structure\": {    \"template\": \"A commercial food photography masterpiece of Authentic Thai Noodle Soup (ก๋วยเตี๋ยว), featuring a steaming bowl of glossy broth with perfectly arranged noodles, tender slices of meat, fresh herbs, and vibrant toppings. Placed in a Warm Gourmet Street Elegance setting featuring a clean wooden table with softly blurred Thai night market lights in the background.\\n\\n**MANDATORY STYLE:** Professional studio lighting with soft directional light from left, subtle rim light, warm reflector fill, Shot on Phase One XF IQ4 150MP, 80mm lens, f/2.8, ultra-high detail, creamy bokeh, color graded, high contrast, vibrant natural tones.\\n\\n**COMPOSITION:** Rule of thirds, clean background, sharp focus on food texture and steam, no clutter. 8k resolution, highly detailed.\"  }}",
