        "MasterPrompt":  "{  \"prompt\": {    \"task\": \"Create a hand-drawn watercolor food illustration.\",    \"core_idea\": {      \"main_subject\": \"Golden crispy Thai fried bananas (กล้วยทอด) stacked naturally, showing irregular crunchy batter texture\",      \"food_name\": \"Thai Fried Bananas\",      \"ingredients\": [        \"ripe bananas (peeled and sliced)\",        \"rice flour batter\",        \"shredded coconut\",        \"sesame seeds\",        \"hot oil splashes (subtle visual hint)\",        \"banana leaves as natural base\"      ],      \"description\": \"The image centers on freshly fried bananas with a warm, crispy, golden appearance. Surrounding ingredients are arranged in a natural, editorial food-journal style to enhance storytelling.\"    },    \"composition\": {      \"view_angle\": \"Slight top-down (30–45 degrees) for depth and visibility\",      \"layout\": \"Main fried bananas placed at center as the hero. Ingredients loosely arranged around in a circular, organic composition.\",      \"balance\": \"Keep composition airy and uncluttered, allowing negative space to enhance the watercolor aesthetic.\"    },    \"text_rules\": {      \"text_language\": \"None\",      \"main_text\": \"None\",      \"secondary_text\": \"None\"    },    \"style\": {      \"technique\": [        \"hand-drawn watercolor illustration\",        \"expressive ink outlines\",        \"soft pigment bleeding edges\",        \"layered transparent washes\"      ],      \"aesthetic\": \"fresh food-journal sketchbook style, artistic and appetizing, painterly but still readable\"    },    \"color\": {      \"color_palette\": \"warm golden yellow, toasted brown, soft cream, natural green, light beige\",      \"guidelines\": \"Colors should feel fresh, warm, and natural with soft watercolor transitions and slight pigment variation.\"    },    \"restrictions\": {      \"no_photorealism\": true,      \"no_3d_render\": true,      \"no_vector\": true,      \"no_dark_background\": true,      \"no_stock_photo_look\": true    }  }}",
